const ciudad = $('Iterar Ciudades').item.json;

return [{
  json: {
    ciudad_nombre: ciudad.ciudad,
    lat: ciudad.lat,
    lon: ciudad.lon,
    temperatura: $json.current_weather.temperature,
    viento: $json.current_weather.windspeed
  }
}];

const temperaturas = items
  .filter(item => item.json.temperatura !== null && item.json.temperatura !== undefined)
  .map(item => ({
    ciudad: item.json.ciudad_nombre,
    temperatura: item.json.temperatura,
    viento: item.json.viento,
  }));

if (temperaturas.length === 0) {
  return [{
    json: {
      clima_regional: {
        error: "No se recibieron temperaturas válidas"
      }
    }
  }];
}

const temps = temperaturas.map(t => t.temperatura);

const promedio = temps.reduce((a, b) => a + b, 0) / temps.length;

const ciudad_mas_caliente = temperaturas.reduce((max, actual) =>
  actual.temperatura > max.temperatura ? actual : max
);

const ciudad_mas_fria = temperaturas.reduce((min, actual) =>
  actual.temperatura < min.temperatura ? actual : min
);

return [{
  json: {
    clima_regional: {
      ciudades_detalle: temperaturas,
      estadisticas: {
        promedio: Number(promedio.toFixed(1)),
        maxima: Math.max(...temps),
        minima: Math.min(...temps),
        ciudad_mas_caliente,
        ciudad_mas_fria
      }
    }
  }
}];

const paises = items.map(item => {
  const pais = item.json;

  const monedaKey = Object.keys(pais.currencies || {})[0];
  const idiomaKey = Object.keys(pais.languages || {})[0];

  return {
    nombre: pais.name?.common || "No disponible",
    capital: pais.capital?.[0] || "No disponible",
    poblacion: pais.population || 0,
    area: pais.area || 0,
    densidad: pais.area
      ? Number((pais.population / pais.area).toFixed(2))
      : 0,
    moneda: monedaKey
      ? pais.currencies[monedaKey].name
      : "No disponible",
    idioma_oficial: idiomaKey
      ? pais.languages[idiomaKey]
      : "No disponible"
  };
});

return [{
  json: {
    contexto_pais: paises
  }
}];

if ($json.statusCode || $json.error || !$json.docs) {

  return [{
    json: {
      error: {
        nodo: "Libros",
        fuente: "open-library",
        mensaje:
          $json.message ||
          $json.error?.message ||
          "Error en Open Library",
        timestamp: new Date().toISOString()
      }
    }
  }];

}

const libros = $json.docs
  .filter(libro =>
    libro.first_publish_year &&
    libro.first_publish_year >= 2015
  )
  .slice(0, 10)
  .map(libro => ({
    titulo: libro.title,
    autor: libro.author_name?.[0] || "Autor desconocido",
    anio: libro.first_publish_year
  }));

return [{
  json: {
    recursos_academicos: libros
  }
}];

const salida = {
  reporte: {
    version: "1.0",
    timestamp: new Date().toISOString(),
    estado: "completo",
    fuentes: ["open-meteo", "rest-countries", "open-library"],
    clima_regional: null,
    contexto_pais: null,
    recursos_academicos: null,
    errores: []
  }
};

for (const item of items) {
  if (item.json.clima_regional) salida.reporte.clima_regional = item.json.clima_regional;
  if (item.json.contexto_pais) salida.reporte.contexto_pais = item.json.contexto_pais;
  if (item.json.recursos_academicos) salida.reporte.recursos_academicos = item.json.recursos_academicos;

  if (item.json.error || item.json.message || item.json.statusCode >= 400) {
    salida.reporte.estado = "incompleto";
    salida.reporte.errores.push({
      nodo: item.json.node || "Nodo con error",
      mensaje: item.json.error?.message || item.json.message || "Error detectado en una rama",
      timestamp: new Date().toISOString()
    });
  }
}

return [{ json: salida }];
